+    return true;
+  } catch {
+    return false;
+  }
+}
+
+/**
+ * Initialize GNN module (if needed)
+ */
+export function initGNN(): void {
+  if (typeof gnn.init === 'function') {
+    gnn.init();
+  }
+}
+
+// Export original for advanced users who want direct access
+export { gnn as gnnRaw };
+
